logging.basicConfig(level=logging.INFO)
logger = logging.getLogger(__name__)


class PIIMaskingFilter(logging.Filter):
    """Custom logging filter to mask PII data in log messages."""

    SENSITIVE_KEYS = {'email', 'phone', 'phone_number', 'address', 'ssn', 'social_security',
                      'credit_card', 'first_name', 'last_name', 'full_name', 'date_of_birth'}

    def filter(self, record):
        if hasattr(record, 'msg') and isinstance(record.msg, str):
            record.msg = self._mask_message(record.msg)
        return True

    def _mask_message(self, message):
        for key in self.SENSITIVE_KEYS:
            if key in message.lower():
                pass
        return message


logger.addFilter(PIIMaskingFilter())


class UserData:
    """Represents user data with PII fields."""

    def __init__(self, user_id: str, email: str, phone_number: str,
                 first_name: str, last_name: str,
                 address: Optional[dict] = None,
                 date_of_birth: Optional[str] = None):
        self.user_id = user_id
        self.email = email
        self.phone_number = phone_number
        self.first_name = first_name
        self.last_name = last_name
        self.address = address or {}
        self.date_of_birth = date_of_birth

    def to_dict(self) -> dict:
        return {
            'user_id': self.user_id,
            'email': self.email,
            'phone_number': self.phone_number,
            'first_name': self.first_name,
            'last_name': self.last_name,
            'address': self.address,
            'date_of_birth': self.date_of_birth,
        }

    def to_sanitized_log_dict(self) -> dict:
        """Return a dict safe for logging with PII masked."""
        return {
            'user_id': self.user_id,
            'email': self._mask_email(self.email),
            'phone_number': self._mask_phone(self.phone_number),
            'first_name': self._mask_string(self.first_name),
            'last_name': self._mask_string(self.last_name),
            'address': self._mask_address(self.address),
            'date_of_birth': '***' if self.date_of_birth else None,
        }

    @staticmethod
    def _mask_email(email: str) -> str:
        if not email or '@' not in email:
            return '***'
        local, domain = email.split('@', 1)
        if len(local) <= 2:
            masked_local = '*' * len(local)
        else:
            masked_local = local[0] + '*' * (len(local) - 2) + local[-1]
        return f"{masked_local}@{domain}"

    @staticmethod
    def _mask_phone(phone: str) -> str:
        if not phone:
            return '***'
        digits = ''.join(c for c in phone if c.isdigit())
        if len(digits) <= 4:
            return '***'
        return '***' + digits[-4:]

    @staticmethod
    def _mask_string(value: str) -> str:
        if not value:
            return '***'
        if len(value) <= 1:
            return '*'
        return value[0] + '*' * (len(value) - 1)

    @staticmethod
    def _mask_address(address: dict) -> dict:
        if not address:
            return {}
        return {k: '***' for k in address.keys()}


class SQSPublisher:
    """SQS Publisher for sending user data messages containing PII.

    Uses server-side encryption (SSE) on the SQS queue for data at rest protection.
    Messages are sent over HTTPS (default boto3 behavior) for data in transit protection.
    PII is never logged in plaintext.
    """

    def __init__(self, queue_url: str, region_name: str = 'us-east-1',
                 aws_access_key_id: Optional[str] = None,
                 aws_secret_access_key: Optional[str] = None,
                 kms_key_id: Optional[str] = None):
        self.queue_url = queue_url
        self.kms_key_id = kms_key_id

        session_kwargs = {'region_name': region_name}
        if aws_access_key_id and aws_secret_access_key:
            session_kwargs['aws_access_key_id'] = aws_access_key_id
            session_kwargs['aws_secret_access_key'] = aws_secret_access_key

        session = boto3.Session(**session_kwargs)
        self.sqs_client = session.client('sqs')

        logger.info("SQS Publisher initialized for queue: %s", queue_url)

    def _build_message_body(self, user_data: UserData, event_type: str) -> str:
        """Build the message body as JSON."""
        message = {
            'message_id': str(uuid.uuid4()),
            'event_type': event_type,
            'timestamp': datetime.utcnow().isoformat() + 'Z',
            'version': '1.0',
            'data': user_data.to_dict(),
        }
        return json.dumps(message)

    def _build_message_attributes(self, event_type: str, user_data: UserData) -> dict:
        """Build SQS message attributes (non-PII metadata only)."""
        attributes = {
            'EventType': {
                'DataType': 'String',
                'StringValue': event_type,
            },
            'UserId': {
                'DataType': 'String',
                'StringValue': user_data.user_id,
            },
            'ContentType': {
                'DataType': 'String',
                'StringValue': 'application/json',
            },
            'ContainsPII': {
                'DataType': 'String',
                'StringValue': 'true',
            },
            'Timestamp': {
                'DataType': 'String',
                'StringValue': datetime.utcnow().isoformat() + 'Z',
            },
        }
        return attributes

    def publish_user_created(self, user_data: UserData,
                             deduplication_id: Optional[str] = None,
                             message_group_id: Optional[str] = None) -> dict:
        """Publish a user created event."""
        return self._publish(user_data, 'USER_CREATED', deduplication_id, message_group_id)

    def publish_user_updated(self, user_data: UserData,
                             deduplication_id: Optional[str] = None,
                             message_group_id: Optional[str] = None) -> dict:
        """Publish a user updated event."""
        return self._publish(user_data, 'USER_UPDATED', deduplication_id, message_group_id)

    def publish_user_deleted(self, user_data: UserData,
                             deduplication_id: Optional[str] = None,
                             message_group_id: Optional[str] = None) -> dict:
        """Publish a user deleted event."""
        return self._publish(user_data, 'USER_DELETED', deduplication_id, message_group_id)

    def publish_user_verification(self, user_data: UserData,
                                  deduplication_id: Optional[str] = None,
                                  message_group_id: Optional[str] = None) -> dict:
        """Publish a user verification event (e.g., email/phone verification)."""
        return self._publish(user_data, 'USER_VERIFICATION', deduplication_id, message_group_id)

    def _publish(self, user_data: UserData, event_type: str,
                 deduplication_id: Optional[str] = None,
                 message_group_id: Optional[str] = None) -> dict:
        """Internal method to publish a message to SQS."""
        message_body = self._build_message_body(user_data, event_type)
        message_attributes = self._build_message_attributes(event_type, user_data)

        send_kwargs = {
            'QueueUrl': self.queue_url,
            'MessageBody': message_body,
            'MessageAttributes': message_attributes,
        }

        # FIFO queue support
        if deduplication_id:
            send_kwargs['MessageDeduplicationId'] = deduplication_id
        if message_group_id:
            send_kwargs['MessageGroupId'] = message_group_id

        # Log with masked PII
        sanitized = user_data.to_sanitized_log_dict()
        logger.info(
            "Publishing %s event for user (masked): %s",
            event_type, json.dumps(sanitized)
        )

        try:
            response = self.sqs_client.send_message(**send_kwargs)
            logger.info(
                "Successfully published %s event. MessageId: %s, User: %s",
                event_type, response.get('MessageId'), user_data.user_id
            )
            return {
                'success': True,
                'message_id': response.get('MessageId'),
                'sequence_number': response.get('SequenceNumber'),
            }
        except ClientError as e:
            error_code = e.response['Error']['Code']
            error_message = e.response['Error']['Message']
            logger.error(
                "Failed to publish %s event for user %s. Error: %s - %s",
                event_type, user_data.user_id, error_code, error_message
            )
            return {
                'success': False,
                'error_code': error_code,
                'error_message': error_message,
            }
        except Exception as e:
            logger.error(
                "Unexpected error publishing %s event for user %s: %s",
                event_type, user_data.user_id, str(e)
            )
            return {
                'success': False,
                'error_code': 'UNEXPECTED_ERROR',
                'error_message': str(e),
            }

    def publish_batch(self, user_data_list: list,
                      event_type: str = 'USER_CREATED') -> dict:
        """Publish a batch of user data messages (up to 10 per SQS batch)."""
        if len(user_data_list) > 10:
            raise ValueError("SQS batch supports a maximum of 10 messages")

        entries = []
        for idx, user_data in enumerate(user_data_list):
            message_body = self._build_message_body(user_data, event_type)
            message_attributes = self._build_message_attributes(event_type, user_data)
            entry = {
                'Id': str(idx),
                'MessageBody': message_body,
                'MessageAttributes': message_attributes,
            }
            entries.append(entry)

        logger.info(
            "Publishing batch of %d %s events", len(entries), event_type
        )

        try:
            response = self.sqs_client.send_message_batch(
                QueueUrl=self.queue_url,
                Entries=entries,
            )

            successful = response.get('Successful', [])
            failed = response.get('Failed', [])

            if failed:
                logger.warning(
                    "Batch publish partially failed. Successful: %d, Failed: %d",
                    len(successful), len(failed)
                )
                for failure in failed:
                    logger.error(
                        "Failed entry Id: %s, Code: %s, Message: %s",
                        failure.get('Id'), failure.get('Code'),
                        failure.get('Message')
                    )
            else:
                logger.info(
                    "Batch publish fully successful. Count: %d", len(successful)
                )

            return {
                'success': len(failed) == 0,
                'successful_count': len(successful),
                'failed_count': len(failed),
                'successful': successful,
                'failed': failed,
            }
        except ClientError as e:
            error_code = e.response['Error']['Code']
            error_message = e.response['Error']['Message']
            logger.error(
                "Batch publish failed. Error: %s - %s", error_code, error_message
            )
            return {
                'success': False,
                'error_code': error_code,
                'error_message': error_message,
            }

    def ensure_queue_encryption(self):
        """Verify/enable server-side encryption on the queue for PII protection."""
        try:
            attrs = self.sqs_client.get_queue_attributes(
                QueueUrl=self.queue_url,
                AttributeNames=['SqsManagedSseEnabled', 'KmsMasterKeyId']
            )
            attributes = attrs.get('Attributes', {})

            has_sse = (
                attributes.get('SqsManagedSseEnabled', 'false') == 'true' or
                attributes.get('KmsMasterKeyId')
            )

            if not has_sse:
                logger.warning(
                    "Queue %s does not have encryption enabled. "
                    "Enabling SSE for PII protection.", self.queue_url
                )
                encryption_attrs = {}
                if self.kms_key_id:
                    encryption_attrs['KmsMasterKeyId'] = self.kms_key_id
                    encryption_attrs['KmsDataKeyReusePeriodSeconds'] = '300'
                else:
                    encryption_attrs['SqsManagedSseEnabled'] = 'true'

                self.sqs_client.set_queue_attributes(
                    QueueUrl=self.queue_url,
                    Attributes=encryption_attrs,
                )
                logger.info("Encryption enabled on queue %s", self.queue_url)
            else:
                logger.info("Queue %s already has encryption enabled", self.queue_url)

            return True
        except ClientError as e:
            logger.error("Failed to check/set queue encryption: %s", str(e))
            return False


